sys_script_client.script:
function onSubmit() {

    var stage =
        g_form.getValue('loan_stage');

    var outstanding =
        g_form.getValue(
            'outstanding_amount'
        );

    if (outstanding.indexOf(';') > -1)
        outstanding =
            outstanding.split(';')[1];

    outstanding =
        parseFloat(
            outstanding.replace(/,/g, '')
        ) || 0;

    if (
        stage == 'x_loan_closure' &&
        outstanding > 0
    ) {

        g_form.addErrorMessage(
            'Outstanding Amount must be zero before Loan Closure.'
        );

        return false;
    }

    return true;
}
